                        <span className={`block text-lg font-semibold ${
                          answers[steps[currentStep].id] === option.value
                            ? 'text-navy-deep'
                            : 'text-navy-deep group-hover:text-gold-primary'
                        }`}>
                          {option.label}
                        </span>
                        {option.sublabel && (
                          <span className="mt-1 block text-sm text-slate-dark/50">
                            {option.sublabel}
                          </span>
