                    onClick={handleBack}
                    className="mt-8 inline-flex items-center gap-1.5 font-medium text-navy-medium transition-colors hover:text-gold-primary"
                  >
                    <ChevronLeft className="h-4 w-4" aria-hidden="true" />
                    Back
                  </button>
